// CATEGORY BROWSE — entries filtered to one category
// ═══════════════════════════════════════════════════════════════════════════
export function LegalLibraryBrowse({ legalLang, setLegalLang, categoryFilter, onOpenEntry, onBack, jurisdictions = [] }) {
  const isRTL = RTL_LEGAL_LANGS.has(legalLang);
  const meta = CATEGORY_META[categoryFilter] || { icon: "📄", label: categoryFilter || "Guides", desc: "" };
  const allEntries = LEGAL_ENTRIES_BY_CATEGORY[categoryFilter] || [];

  // Jurisdiction filtering: town/village entries filter to user's location.
  // Federal, state, and county entries always show.
  const [showAll, setShowAll] = React.useState(false);
  const hasGeo = jurisdictions.length > 0;

  // Build jurisdiction slugs from geo matches: "Sweden" + "town" → "sweden-town"
  const geoSlugs = jurisdictions.map(j =>
    j.name.toLowerCase().replace(/\s+/g, '-') + '-' + j.tier
  );

  const filteredEntries = (!hasGeo || showAll) ? allEntries : allEntries.filter(entry => {
    // Always show federal, state, county entries
    if (entry.tier === 'federal' || entry.tier === 'state' || entry.tier === 'county') return true;
    // Town/village/city entries: check if jurisdiction matches any geo slug
    return geoSlugs.some(slug => entry.jurisdiction && entry.jurisdiction.endsWith(slug));
  });

  const entries = filteredEntries;
  const hiddenCount = allEntries.length - filteredEntries.length;

  return (
    <main dir={isRTL ? "rtl" : "ltr"} style={{ padding: "0 20px 40px", maxWidth: 920, margin: "0 auto" }}>
      <button onClick={onBack} style={{ background: "none", border: "none", cursor: "pointer", fontSize: 14, color: C.stone, padding: "16px 0", fontFamily: "inherit" }}>← All topics</button>

      <div style={{ display: "flex", alignItems: "center", gap: 14, marginBottom: 8 }}>
        <div style={{ fontSize: 40, lineHeight: 1 }}>{meta.icon}</div>
        <h1 style={{ fontFamily: SERIF, fontSize: 32, fontWeight: 400, margin: 0, color: C.bark, lineHeight: 1.2 }}>{meta.label}</h1>
      </div>
      <p style={{ fontSize: 14, color: C.stone, marginBottom: 6, lineHeight: 1.6 }}>{meta.desc}</p>
      <p style={{ fontSize: 12, color: C.dust, marginBottom: hasGeo && !showAll && hiddenCount > 0 ? 8 : 22 }}>
        {entries.length} guide{entries.length === 1 ? "" : "s"}
        {hasGeo && !showAll ? " for " + jurisdictions.map(j => j.displayName || j.name).join(" + ") : ""}
      </p>
      {hasGeo && hiddenCount > 0 && (
        <button
          onClick={() => setShowAll(!showAll)}
          style={{
            background: "none", border: "none", cursor: "pointer",
            fontSize: 12, color: C.forest, padding: "0 0 14px", fontFamily: "inherit",
            textDecoration: "underline"
          }}
        >
          {showAll ? "Show my area only" : "Show all " + allEntries.length + " jurisdictions"}
        </button>
      )}

      <LanguagePicker legalLang={legalLang} setLegalLang={setLegalLang} />

      {/* Entry list */}
      <div style={{ display: "grid", gap: 12 }}>
        {entries.map((entry) => (
          <button
            key={entry.id}
            onClick={() => onOpenEntry(entry.id)}
            style={{
              textAlign: isRTL ? "right" : "left",
              background: C.white,
              border: "1px solid " + C.border,
              borderRadius: 12,
              padding: "14px 18px",
              cursor: "pointer",
              fontFamily: "inherit",
              boxShadow: "0 1px 2px rgba(0,0,0,0.02)",
              width: "100%",
            }}
          >
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
              <span style={{ fontSize: 10, fontWeight: 700, color: C.forest, background: C.sage, padding: "3px 8px", borderRadius: 6, textTransform: "uppercase", letterSpacing: 0.5 }}>{entry.tier}</span>
              {entry.jurisdiction && (
                <span style={{ fontSize: 10, color: C.dust, textTransform: "uppercase", letterSpacing: 0.5 }}>{entry.jurisdiction}</span>
              )}
            </div>
            <div style={{ fontSize: 16, fontWeight: 600, color: C.bark, marginBottom: 4, lineHeight: 1.3 }}>
              {pickText(entry.title, legalLang)}
            </div>
            <div style={{ fontSize: 13, color: C.stone, lineHeight: 1.55 }}>
              {pickText(entry.summary, legalLang)}
            </div>
          </button>
        ))}
      </div>

      <div style={{ marginTop: 28, padding: "14px 18px", background: C.amberLight, borderRadius: 12, border: "1px solid #f0dab0", fontSize: 13, color: C.stone, lineHeight: 1.6 }}>
        ⚠️ <strong>Not legal advice.</strong> These guides explain your general rights under New York and federal law. Laws change. For your specific situation, use the free legal aid resources listed in each guide.
      </div>
    </main>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// SHARE BAR — share individual entry pages to socials, text, email, or copy link
// ═══════════════════════════════════════════════════════════════════════════
function ShareBar({ entryId, title }) {
  const [copied, setCopied] = React.useState(false);
  const url = "https://helpfinder.help/know-your-rights/" + entryId;
  const text = title + " — free legal guide from HelpFinder, the only .help you need";
  const encodedUrl = encodeURIComponent(url);
  const encodedText = encodeURIComponent(text);

  const copyLink = () => {
    navigator.clipboard.writeText(url).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }).catch(() => {
      const ta = document.createElement("textarea");
      ta.value = url;
      document.body.appendChild(ta);
      ta.select();
      document.execCommand("copy");
      document.body.removeChild(ta);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  const nativeShare = () => {
    if (navigator.share) {
      navigator.share({ title: title, text: text, url: url }).catch(() => {});
    }
  };

  const btnBase = {
    display: "inline-flex", alignItems: "center", justifyContent: "center",
    gap: 5, padding: "7px 12px", borderRadius: 8, border: "1px solid " + C.border,
    background: C.white, cursor: "pointer", fontFamily: "inherit",
    fontSize: 12, fontWeight: 600, lineHeight: 1, whiteSpace: "nowrap",
  };

  return (
    <div style={{ display: "flex", flexWrap: "wrap", gap: 6, alignItems: "center", margin: "16px 0" }}>
      <span style={{ fontSize: 12, color: C.dust, fontWeight: 600, marginRight: 4 }}>Share:</span>
      <button onClick={copyLink} style={{ ...btnBase, color: copied ? C.forest : C.bark, background: copied ? C.sage : C.white }}>
        {copied ? "Copied" : "Copy link"}
      </button>
      <a href={"https://www.facebook.com/sharer/sharer.php?u=" + encodedUrl} target="_blank" rel="noopener noreferrer"
        style={{ ...btnBase, color: "#1877F2", textDecoration: "none" }}>
        Facebook
      </a>
      <a href={"https://twitter.com/intent/tweet?url=" + encodedUrl + "&text=" + encodedText} target="_blank" rel="noopener noreferrer"
        style={{ ...btnBase, color: "#000", textDecoration: "none" }}>
        X
      </a>
      <a href={"mailto:?subject=" + encodeURIComponent(title) + "&body=" + encodedText + "%0A%0A" + encodedUrl}
        style={{ ...btnBase, color: C.bark, textDecoration: "none" }}>
        Email
      </a>
      <a href={"sms:?body=" + encodedText + " " + encodedUrl}
        style={{ ...btnBase, color: C.forest, textDecoration: "none" }}>
        Text
      </a>
      {typeof navigator !== "undefined" && navigator.share && (
        <button onClick={nativeShare} style={{ ...btnBase, color: C.forest }}>
          More
        </button>
      )}
    </div>
  );
}

